/* إعادة تصميم شريط النظام الأزرق ليصبح متناسقاً مع الواجهة */
.navbar.navbar-light.bg-white, 
.navbar, 
header .navbar {
    background: rgba(9, 38, 30, 0.85) !important;
    backdrop-filter: blur(15px) !important;
    border-bottom: 1px solid rgba(181, 124, 0, 0.4) !important;
}

/* تغيير ألوان النصوص والروابط داخل شريط النظام إلى الأبيض والذهبي */
.navbar .nav-link, 
.navbar .navbar-brand,
.navbar-nav .nav-link {
    color: #ffffff !important;
    font-weight: 700 !important;
}

.navbar .nav-link:hover {
    color: #ffb300 !important;
}
/* تحويل تذييل النظام الافتراضي إلى المظهر الداكن والذهبي */
footer, .web-footer, .website-footer {
    background: rgba(6, 26, 20, 0.85) !important;
    backdrop-filter: blur(15px) !important;
    border-top: 1px solid rgba(181, 124, 0, 0.3) !important;
    color: #ffffff !important;
    padding: 30px 0 !important;
}

/* تعديل ألوان النصوص والروابط بالداخل لتناسب الخلفية الداكنة */
footer a, footer p, footer span, footer div {
    color: rgba(255, 255, 255, 0.8) !important;
}

footer a:hover {
    color: #ffb300 !important;
}

/* تعديل حقل المدخلات وزر الاشتراك المكتوب بالإنجليزية إذا أردت الإبقاء عليهما */
footer .input-group input, footer input[type="email"] {
    background: rgba(255, 255, 255, 0.05) !important;
    border: 1px solid rgba(181, 124, 0, 0.4) !important;
    color: #ffffff !important;
}

footer .btn-primary, footer button {
    background: #b57c00 !important;
    border-color: #b57c00 !important;
    color: #0c3328 !important;
    font-weight: 700;
}

javascript:
frappe.ui.form.on('active_taq', { // استبدل active_taq باسم الدوكتايب الحالي لصفحة الأنشطة إذا كان مختلفاً
    refresh: function(frm) {
        // إضافة زر الانتقال الجغرافي في أعلى الصفحة إذا كانت الإحداثيات موجودة
        if (frm.doc.locc) {
            frm.add_custom_button(__('الانتقال الجغرافي للموقع'), function() {
                if (frm.doc.locc) {
                    window.open(`https://maps.google.com/?q=${frm.doc.locc}`, '_blank');
                } else {
                    frappe.msgprint(__('لم يتم العثور على إحداثيات الموقع جغرافيًا'));
                }
            }, __('الإجراءات'));
        }
    },
    
    // عند تغيير أو اختيار المكتب (mak) يتم استجلاب موقع المكتب من العلاقة المتداخلة تلقائياً
    mak: function(frm) {
        if (frm.doc.mak) {
            // 1. جلب حقل loc_mak من دوكتايب mak_taq
            frappe.db.get_value('mak_taq', frm.doc.mak, 'loc_mak')
                .then(r => {
                    let loc_mak = r.message.loc_mak;
                    if (loc_mak) {
                        // 2. جلب حقل الإحداثيات loc من دوكتايب loc_taq
                        frappe.db.get_value('loc_taq', loc_mak, 'loc')
                            .then(res => {
                                let coordinates = res.message.loc;
                                if (coordinates) {
                                    // 3. تخزين الإحداثيات في الحقل الحالي للنشاط (مثلاً locc) ليتم استخدامه في الزر
                                    frm.set_value('locc', coordinates);
                                } else {
                                    frm.set_value('locc', '');
                                }
                            });
                    } else {
                        frm.set_value('locc', '');
                    }
                });
        } else {
            frm.set_value('locc', '');
        }
    }
});

