{% set act = frappe.get_doc("active_taq", activity_id) if (activity_id and frappe.db.exists("active_taq", activity_id)) else None %}

{# جلب البيانات الجغرافية مباشرة عبر الربط المباشر المكتشف #}
{% set raw_geo_data = "" %}
{% if act and act.locc and frappe.db.exists("loc_taq", act.locc) %}
    {% set loc_doc = frappe.get_doc("loc_taq", act.locc) %}
    {% if loc_doc and loc_doc.loc %}
        {% set raw_geo_data = loc_doc.loc %}
    {% endif %}
{% endif %}

