<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>

<script>
document.addEventListener('DOMContentLoaded', function () {
    // إدارة القائمة الجانبية
    var cosmicContainer = document.getElementById('cosmicContainer');
    var sidebarToggleBtn = document.getElementById('sidebarToggleBtn');
    var toggleButtonIcon = document.getElementById('toggleButtonIcon');
    if (sidebarToggleBtn && cosmicContainer && toggleButtonIcon) {
        sidebarToggleBtn.addEventListener('click', function() {
            cosmicContainer.classList.toggle('sidebar-open');
            toggleButtonIcon.className = cosmicContainer.classList.contains('sidebar-open') ? "fa-solid fa-xmark" : "fa-solid fa-bars";
        });
    }

    // الإحداثيات الافتراضية (طرابلس)
    var destinationLat = 32.8872;
    var destinationLng = 13.1931;
    var statusEl = document.getElementById('dbGeoStatus');

    // استخلاص البيانات الجغرافية
    var rawGeoStr = `{{ raw_geo_data }}`.trim();

    if (rawGeoStr) {
        try {
            var geoJSON = JSON.parse(rawGeoStr);
            if (geoJSON && geoJSON.features && geoJSON.features.length > 0) {
                var coords = geoJSON.features[0].geometry.coordinates;
                destinationLng = parseFloat(coords[0]);
                destinationLat = parseFloat(coords[1]);
                statusEl.className = "text-success";
                statusEl.innerHTML = '<i class="fa-solid fa-check-double"></i> تم قراءة بيانات الموقع الصحيحة بنجاح.';
            }
        } catch (e) {
            var parts = rawGeoStr.split(',');
            if (parts.length === 2) {
                var pLat = parseFloat(parts[0]);
                var pLng = parseFloat(parts[1]);
                if (!isNaN(pLat) && !isNaN(pLng)) {
                    destinationLat = pLat;
                    destinationLng = pLng;
                    statusEl.className = "text-success";
                    statusEl.innerHTML = '<i class="fa-solid fa-check-double"></i> تم تحديد الإحداثيات النصية بنجاح.';
                }
            } else {
                statusEl.className = "text-danger";
                statusEl.innerHTML = '<i class="fa-solid fa-triangle-exclamation"></i> خطأ في صيغة البيانات، تم تطبيق الموقع الافتراضي.';
            }
        }
    } else {
        statusEl.className = "text-danger";
        statusEl.innerHTML = '<i class="fa-solid fa-triangle-exclamation"></i> الحقل فارغ، يرجى ملء موقع الخريطة داخل لوحة التحكم.';
    }

    // بناء وتثبيت الخريطة
    var map = L.map('awqafLiveMap').setView([destinationLat, destinationLng], 15);
    
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
    }).addTo(map);

    // تثبيت ماركر الوجهة المستهدفة
    var destMarker = L.marker([destinationLat, destinationLng]).addTo(map)
        .bindPopup('<b>مقر إقامة المنشط العلمي</b>').openPopup();

    var statusBox = document.getElementById('locationStatusBox');
    var statusText = document.getElementById('statusText');
    var metricsPanel = document.getElementById('routingOutputPanel');
    var currentPolyline = null;

    // استدعاء موقع الـ GPS للمستخدم والربط البري بالطرق
    if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(function (position) {
            var userLat = position.coords.latitude;
            var userLng = position.coords.longitude;

            // إسقاط ماركر للمستخدم
            L.marker([userLat, userLng]).addTo(map).bindPopup('<b>موقعك الحالي</b>');

            // جلب خط السير الأرضي من محرك التوجيه OSRM المبني على خرائط الشوارع المفتوحة
            var osrmUrl = `https://router.project-osrm.org/route/v1/driving/${userLng},${userLat};${destinationLng},${destinationLat}?overview=full&geometries=geojson`;

            fetch(osrmUrl)
                .then(response => response.json())
                .then(data => {
                    if (data.code === 'Ok' && data.routes.length > 0) {
                        var route = data.routes[0];
                        var routeCoords = route.geometry.coordinates;
                        
                        // تحويل الترتيب من [Lng, Lat] إلى [Lat, Lng] لتتوافق مع Leaflet
                        var leafletCoords = routeCoords.map(coord => [coord[1], coord[0]]);

                        // رسم المسار الأرضي الحقيقي المتعرج على الشوارع
                        currentPolyline = L.polyline(leafletCoords, {
                            color: '#b57c00',
                            weight: 6,
                            opacity: 0.9,
                            lineJoin: 'round'
                        }).addTo(map);

                        // ضبط كاميرا الخريطة لتشمل نقطة البداية والنهاية والمنعطفات
                        map.fitBounds(currentPolyline.getBounds(), { padding: [50, 50] });

                        // استخراج المسافة والوقت الحقيقيين من مسار الطريق
                        var realDistanceKm = (route.distance / 1000).toFixed(2);
                        var durationMin = Math.round(route.duration / 60);

                        document.getElementById('routeDistance').innerText = realDistanceKm + " كم";
                        document.getElementById('routeDuration').innerText = durationMin + " دقيقة";
                        
                        statusBox.className = "status-indicator-box success";
                        statusText.innerHTML = '<i class="fa-solid fa-circle-check ml-1"></i> تم رسم مسار السير الأرضي الفعلي عبر الطرق.';
                        metricsPanel.classList.remove('d-none');
                    } else {
                        fallbackToStraightLine(userLat, userLng, destinationLat, destinationLng);
                    }
                })
                .catch(err => {
                    fallbackToStraightLine(userLat, userLng, destinationLat, destinationLng);
                });

        }, function (error) {
            statusBox.className = "status-indicator-box failed";
            statusText.innerText = "تعذر تحديد موقعك الحالي. تم عرض موقع المنشط المستهدف فقط.";
        }, {
            enableHighAccuracy: true,
            timeout: 7000
        });
    } else {
        statusBox.className = "status-indicator-box failed";
        statusText.innerText = "المتصفح لا يدعم تتبع نظام الـ GPS.";
    }

    // دالة احتياطية لرسم خط مستقيم في حال انقطاع اتصال خادم التوجيه الخارجي
    function fallbackToStraightLine(uLat, uLng, dLat, dLng) {
        var points = [[uLat, uLng], [dLat, dLng]];
        currentPolyline = L.polyline(points, {
            color: '#b57c00',
            weight: 5,
            opacity: 0.75,
            dashArray: '8, 12'
        }).addTo(map);
        map.fitBounds(currentPolyline.getBounds(), { padding: [40, 40] });
        
        statusBox.className = "status-indicator-box success";
        statusText.innerHTML = '<i class="fa-solid fa-circle-check ml-1"></i> تعذر الاتصال بخادم الطرق، تم عرض المسار المستقيم مؤقتاً.';
    }
});
</script>

