{#
    ==========================================================================
    الصفحة الرئيسية للموقع (home)
    نفس نظام التصميم والسايد بار المستخدم في صفحات الأنشطة والخريطة.

    الأقسام الرئيسية:
    1) قسم "فضيلة الوعاظ" من دوكتايب waed_info (مفلتر ليعرض المستمرين فقط)
    2) قسم "الأنشطة والفعاليات" من دوكتايب active_taq
    ==========================================================================
#}

{% set preachers = frappe.get_all("waed_info", 
    fields=["name", "namee"], 
    filters={"waed_status": "Ongoing"}, 
    limit_page_length=8, 
    order_by="creation desc") %}

{% set activities = frappe.get_all("active_taq", 
    fields=["name", "en", "ty", "assignment_type", "da", "mak", "significant_event"], 
    filters={"docstatus": 0, "workflow_state_wa": "تكليف معتمد"}, 
    order_by="significant_event desc, da desc",
    limit_page_length=4) %}

<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;900&family=Amiri:wght@700&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">

<div class="awqaf-cosmic-container" id="cosmicContainer" dir="rtl">
    
    <!-- خطوط الخلفية الفنية -->
    <div class="bg-arabic-calligraphy top-right">البِرُّ وَالتَّقْوَى</div>
    <div class="bg-arabic-calligraphy bottom-left">الشُّؤُونُ الدَّعْوِيَّة</div>

    <!-- زر فتح وإغلاق القائمة الجانبية -->
    <button class="awqaf-sidebar-toggle-bar" id="sidebarToggleBtn" title="فتح/إغلاق القائمة">
        <span class="toggle-bar-text">القائمة الرئيسية</span>
        <div class="toggle-bar-icon-box">
            <i class="fa-solid fa-bars" id="toggleButtonIcon"></i>
        </div>
    </button>

    <!-- السايد بار الزجاجي الموحد -->
    <aside class="awqaf-glass-sidebar">
        <div class="sidebar-header">
            <div class="sidebar-brand">
                <i class="fa-solid fa-mosque golden-text"></i>
                <span>لوحة التنقل</span>
            </div>
        </div>
        <nav class="sidebar-nav">
            <a href="/home" class="nav-item active">
                <i class="fa-solid fa-house-user"></i>
                <span>الرئيسية</span>
            </a>
            <a href="/active-taq-web" class="nav-item">
                <i class="fa-solid fa-scroll"></i>
                <span>الأنشطة والفعاليات</span>
            </a>
            <a href="/album-photo" class="nav-item">
                <i class="fa-solid fa-images"></i>
                <span>ألبوم الصور</span>
            </a>
            <a href="/about-us" class="nav-item">
                <i class="fa-solid fa-kaaba"></i>
                <span>حول الإدارة</span>
            </a>
            <a href="/call-us" class="nav-item">
                <i class="fa-solid fa-envelope-open-text"></i>
                <span>اتصل بنا</span>
            </a>
        </nav>
        <div class="sidebar-footer">
            <div class="poster-deco-line"></div>
            <small>© الهيئة العامة للأوقاف</small>
        </div>
    </aside>

    <!-- محتوى الكون الرئيسي -->
    <div class="awqaf-main-content-universe">
        <div class="container py-5 position-relative" style="z-index: 3;">

            <!-- ===== الهيدر الرئيسي الفاخر ===== -->
            <div class="awqaf-poster-header text-center mb-5">
                <div class="golden-emblem-wrapper mb-3">
                    <i class="fa-solid fa-mosque golden-icon-3d"></i>
                    <div class="golden-glow"></div>
                </div>
                <h2 class="poster-main-title golden-text-3d">الهيئة العامة للأوقاف والشؤون الإسلامية</h2>
                <p class="poster-sub-title mb-0">إدارة الشؤون الثقافية والدعوية - بوابة الأنشطة والوعاظ والفعاليات العلمية</p>
                <div class="poster-deco-line"></div>
            </div>

            <!-- ===== قسم: الرسالة التوجيهية للإدارة ===== -->
            <div class="awqaf-mission-banner text-center">
                <div class="row justify-content-center">
                    <div class="col-lg-10 col-12">
                        <span class="mission-tag"><i class="fa-solid fa-kaaba"></i> رسالتنا وقيمنا</span>
                        <h4 class="mission-title mt-2">"أصالةٌ في المنهج.. وعصريةٌ في الوسيلة"</h4>
                        <p class="mission-text">
                            تسعى إدارة الشؤون الثقافية والدعوية إلى توظيف التقنيات الحديثة ونظم إدارة الموارد المتطورة لتنظيم وتوثيق الأنشطة العلمية والدروس المنهجية، والإشراف على شؤون فضيلة الوعاظ المعتمدين لضمان إيصال الخطاب الدعوي المعتدل والمستقر لكافة ربوع الوطن، حمايةً للهوية الفكرية وتعزيزاً للقيم الإسلامية السمحة.
                        </p>
                    </div>
                </div>
            </div>

            <!-- ===== قسم فضيلة الوعاظ (waed_info) ===== -->
            <div class="home-section-header d-flex justify-content-between align-items-center">
                <div class="section-title-block">
                    <i class="fa-solid fa-user-tie text-gold"></i>
                    <div>
                        <h3>المنبر الرقمي لفضيلة الوعاظ</h3>
                        <p class="section-sub-desc mb-0">نافذة رسمية معتمدة لاستعراض السير العلمية والنشاط الدعوي المستمر لشيوخنا الأفاضل.</p>
                    </div>
                </div>
                <a href="/waed-info-web" class="btn-see-all">
                    عرض الجميع <i class="fa-solid fa-arrow-left mr-1"></i>
                </a>
            </div>

            <!-- تنويه إداري مخصص للوعاظ -->
            <div class="awqaf-alert-hint">
                <i class="fa-solid fa-circle-info hint-icon"></i>
                <p class="hint-message mb-0"><strong>تنويه:</strong> يتم تحديث قوائم الوعاظ المعروضة على البوابة الخارجية تلقائياً بناءً على مخرجات منظومة سير العمل الداعمة (Workflow)، حيث تقتصر الواجهة الحالية على المستمرين معتمداً (Ongoing) فقط.</p>
            </div>

            <div class="row awqaf-cards-row">
                {% if preachers %}
                    {% for p in preachers %}
                        <div class="col-lg-3 col-md-4 col-6 mb-4">
                            <div class="preacher-home-card">
                                <div class="preacher-avatar">
                                    <i class="fa-solid fa-user-tie"></i>
                                </div>
                                <h6 class="preacher-home-name">{{ p.namee or "فضيلة الشيخ" }}</h6>
                                <span class="preacher-home-badge">واعظ معتمد</span>
                            </div>
                        </div>
                    {% endfor %}
                {% else %}
                    <div class="col-12">
                        <div class="awqaf-empty-poster py-4 text-center">
                            <i class="fa-solid fa-user-tie fa-2x mb-2 text-white-50"></i>
                            <h6 class="text-white-50 mb-0">لا يوجد وعاظ مسجلون حالياً.</h6>
                        </div>
                    </div>
                {% endif %}
            </div>

            <!-- ===== قسم الأنشطة والفعاليات (active_taq) ===== -->
            <div class="home-section-header d-flex justify-content-between align-items-center">
                <div class="section-title-block">
                    <i class="fa-solid fa-scroll text-gold"></i>
                    <div>
                        <h3>الحصاد الدعوي والنشاط العلمي</h3>
                        <p class="section-sub-desc mb-0">توثيق حي وفوري لكافة الدروس المنهجية، والمحاضرات التوجيهية، والندوات العلمية المقامة بالمساجد.</p>
                    </div>
                </div>
                <a href="/active-taq-web" class="btn-see-all">
                    عرض جميع الأنشطة <i class="fa-solid fa-arrow-left ml-1"></i>
                </a>
            </div>

            <!-- إشعار توثيق الأنشطة -->
            <div class="awqaf-alert-hint">
                <i class="fa-solid fa-shield-halved hint-icon"></i>
                <p class="hint-message mb-0"><strong>متابعة فورية:</strong> جميع الأنشطة والفعاليات المعروضة في البوابة مرت بمراحل التدقيق والمراجعة الرقمية وصدرت بها قرارات "تكليف معتمد" من الإدارة المختصة.</p>
            </div>

            <div class="row awqaf-cards-row">
                {% if activities %}
                    {% for act in activities %}
                        <div class="col-lg-6 col-md-6 col-12 mb-4">
                            <a href="/active-taq-web" class="activity-home-card-link">
                                <div class="activity-home-card {{ 'significant-home-card' if act.significant_event else '' }}">
                                    <div class="activity-home-top">
                                        <span class="activity-home-badge">
                                            <i class="fa-solid fa-circle-nodes"></i> {{ act.assignment_type or "تكليف عام" }}
                                        </span>
                                        <span class="activity-home-date">
                                            <i class="fa-regular fa-calendar-days ml-1"></i> {{ act.da or "قريباً" }}
                                        </span>
                                    </div>
                                    <h5 class="activity-home-title">{{ act.en or "نشاط دعوي وعلمي" }}</h5>
                                    <div class="activity-home-bottom">
                                        <span><i class="fa-solid fa-building-columns text-gold-dim"></i> {{ act.mak or "المكتب الإداري" }}</span>
                                        <span class="activity-home-arrow"><i class="fa-solid fa-arrow-left"></i></span>
                                    </div>
                                </div>
                            </a>
                        </div>
                    {% endfor %}
                {% else %}
                    <div class="col-12">
                        <div class="awqaf-empty-poster py-4 text-center">
                            <i class="fa-solid fa-clipboard-list fa-2x mb-2 text-white-50"></i>
                            <h6 class="text-white-50 mb-0">لا توجد أنشطة معتمدة حالياً.</h6>
                        </div>
                    </div>
                {% endif %}
            </div>

            <!-- ===== قسم الخدمات التقنية واللوجستية الفنية ===== -->
            <div class="home-section-header d-flex justify-content-between align-items-center">
                <div class="section-title-block">
                    <i class="fa-solid fa-laptop-code text-gold"></i>
                    <div>
                        <h3>البنية التحتية والخدمات الفنية</h3>
                        <p class="section-sub-desc mb-0">تيسير الإجراءات الإدارية وتوفير الدعم التقني واللوجستي اللازم لتسيير المكاتب الإقليمية بفاعلية.</p>
                    </div>
                </div>
            </div>

            <div class="row awqaf-cards-row">
                <div class="col-12">
                    <div class="awqaf-tech-support-banner">
                        <div class="tech-support-content">
                            <h5><i class="fa-solid fa-file-invoice"></i> نظام بلاغات المكاتب الإقليمية الموحد</h5>
                            <p class="mb-0">
                                في حال وجود أي عطل تقني أو برمججي في الأنظمة الرقمية للمكاتب، يرجى سحب وتنزيل <strong>نموذج بلاغات الأعطال الموحد (A4)</strong> وتعبئته يدوياً بالخط الواضح، ثم رفعه وتسليمه مباشرة إلى قسم الدعم الفني بالإدارة لضمان سرعة المعالجة والصيانة.
                            </p>
                        </div>
                        <div class="tech-support-action">
                            <a href="#" class="btn-download-form"><i class="fa-solid fa-file-pdf"></i> تحميل النموذج الورقي المعين</a>
                        </div>
                    </div>
                </div>
            </div>

            <!-- ===== التذييل الجمالي والأدبي البصري ===== -->
            <div class="awqaf-poetic-footer text-center">
                <p class="poetic-quote">"بالعلمِ تُبنى العقول.. وبالدعوةِ تستقيمُ الصدور"</p>
                <span class="poetic-sub">إدارة الشؤون الثقافية والدعوية: أصالةٌ في المنهج.. وعصريةٌ في الوسيلة</span>
            </div>

        </div>
    </div>
</div>

<style>
    .awqaf-cosmic-container { 
        font-family: 'Tajawal', sans-serif !important; 
        background: radial-gradient(circle at 50% 30%, #0c3328 0%, #071f18 60%, #030f0c 100%); 
        min-height: 100vh; position: relative; overflow: hidden; display: flex; width: 100%;
        transition: padding 0.4s cubic-bezier(0.25, 0.8, 0.25, 1);
    }
    .bg-arabic-calligraphy { position: absolute; font-family: 'Amiri', serif; font-size: 20rem; font-weight: 700; color: rgba(22, 92, 75, 0.32); line-height: 1; user-select: none; pointer-events: none; white-space: nowrap; z-index: 1; }
    .bg-arabic-calligraphy.top-right { top: -30px; right: -50px; transform: rotate(-12deg); }
    .bg-arabic-calligraphy.bottom-left { bottom: -20px; left: -50px; transform: rotate(15deg); }
    .awqaf-main-content-universe { flex: 1; position: relative; z-index: 2; transition: margin-right 0.4s ease; width: 100%; overflow-x: hidden; }
    
    /* عند فتح القائمة، يزاح المحتوى بسلاسة */
    .sidebar-open .awqaf-main-content-universe { margin-right: 290px; } 

    .awqaf-sidebar-toggle-bar { 
        position: fixed; top: 30px; right: 30px; z-index: 1200; display: flex; align-items: center; justify-content: space-between;
        background: rgba(12, 51, 40, 0.75); backdrop-filter: blur(15px); border: 1px solid rgba(181, 124, 0, 0.6);
